sql:
SELECT passenger_id, travel_date, departure
FROM travel_history
WHERE travel_status = 'completed';

SELECT *
FROM transport_modes
WHERE capacity > 200;

SELECT COUNT(DISTINCT th.passenger_id) 
FROM travel_history th 
WHERE th.arrival = 'London';

SELECT DISTINCT p.*
FROM passengers p
JOIN feedback f ON p.passenger_id = f.passenger_id;

external_knowledge:
- "seasoned travelers, beyond the prime of their youth" refers to passengers older than 35 years old;
- "lands other than the United States" means passengers whose nationality is not from the USA;
- "listed in alphabetical order by their names" indicates the results should be sorted by first and last names in ascending order.

sql:
SELECT COUNT(DISTINCT passenger_id)
FROM (
  SELECT passenger_id FROM tickets
  UNION
  SELECT passenger_id FROM alerts
);

SELECT first_name, last_name 
FROM passengers 
WHERE passenger_id IN (
  SELECT passenger_id 
  FROM family_relations
);

SELECT COUNT(DISTINCT passenger_id) AS total_passengers
FROM travel_history
WHERE check_in_time IS NOT NULL AND check_out_time IS NULL;
